&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Shimla Agreement&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Pakistan suspended the Shimla Agreement in retaliation to India&amp;#39;s withdrawal from the Indus Waters Treaty.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The Shimla Agreement was signed between India and Pakistan after the 1971 war to restore peace and resolve issues bilaterally.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;The agreement led to the establishment of the Line of Control (LoC) in Kashmir, replacing the previous ceasefire line.&lt;/li&gt;
	&lt;li&gt;It also facilitated the formal recognition of Bangladesh and the release of 93,000 Pakistani prisoners of war.&lt;/li&gt;
	&lt;li&gt;Pakistan&amp;rsquo;s suspension of the Shimla Agreement came in response to India&amp;rsquo;s move to withdraw from the Indus Waters Treaty.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Lahore Declaration&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;Signed in - 1999&lt;/li&gt;
		&lt;li&gt;Between - India and Pakistan&lt;/li&gt;
		&lt;li&gt;Aimed to strengthen peace and security, and resolve Kashmir conflict&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Tashkent Agreement&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Signed in - 1966&lt;/li&gt;
		&lt;li&gt;Between - India and Pakistan&lt;/li&gt;
		&lt;li&gt;Focus - Restoration of territories captured during the 1965 war&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Karachi Agreement&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Signed in - 1949&lt;/li&gt;
		&lt;li&gt;Between - India and Pakistan&lt;/li&gt;
		&lt;li&gt;Focus - Ceasefire line in Kashmir post-1947 war&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;शिमला समझौता&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;भारत द्वारा सिंधु जल संधि से हटने के जवाब में पाकिस्तान ने शिमला समझौते को निलंबित कर दिया।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;1971 के युद्ध के बाद शांति बहाल करने और द्विपक्षीय मुद्दों को सुलझाने के लिए भारत और पाकिस्तान के बीच शिमला समझौते पर हस्ताक्षर किए गए थे।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;इस समझौते के परिणामस्वरूप कश्मीर में नियंत्रण रेखा (एलओसी) की स्थापना हुई, जिसने पूर्ववर्ती युद्धविराम रेखा का स्थान ले लिया।&lt;/li&gt;
	&lt;li&gt;इसने बांग्लादेश को औपचारिक मान्यता दिलाने तथा 93,000 पाकिस्तानी युद्धबंदियों की रिहाई में भी मदद की।&lt;/li&gt;
	&lt;li&gt;पाकिस्तान द्वारा शिमला समझौते को स्थगित करना भारत द्वारा सिंधु जल संधि से हटने के कदम के जवाब में आया।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;लाहौर घोषणा&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;साइन इन - 1999&lt;/li&gt;
		&lt;li&gt;भारत और पाकिस्तान के बीच&lt;/li&gt;
		&lt;li&gt;इसका उद्देश्य शांति और सुरक्षा को मजबूत करना तथा कश्मीर संघर्ष का समाधान करना है&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;ताशकंद समझौता&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;हस्ताक्षर - 1966&lt;/li&gt;
		&lt;li&gt;भारत और पाकिस्तान के बीच&lt;/li&gt;
		&lt;li&gt;फोकस - 1965 के युद्ध के दौरान कब्जाए गए क्षेत्रों की बहाली&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;कराची समझौता&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;हस्ताक्षर - 1949&lt;/li&gt;
		&lt;li&gt;भारत और पाकिस्तान के बीच&lt;/li&gt;
		&lt;li&gt;फोकस - 1947 के युद्ध के बाद कश्मीर में युद्धविराम रेखा&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;S.P. Sharma.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

